jQuery(document).on("ajaxSuccess",function(e,t,r){const s=new URLSearchParams(r.data);if("submit"!==s.get("quform_submit"))return;let u;try{u=JSON.parse(t.responseText).type}catch(e){return}if("success"!==u)return;const o=s.get("quform_form_id"),c=jQuery('input[name="quform_form_id"][value="'+o+'"]').closest("form");window.ProcaptchaReset(c[0])});